import{_ as a,o as i,c as t,ag as e}from"./chunks/framework.Ca42NP5A.js";const g=JSON.parse('{"title":"Act as a registered agent","description":"","frontmatter":{},"headers":[],"relativePath":"guides/act-as-agent.md","filePath":"guides/act-as-agent.md","lastUpdated":null}'),n={name:"guides/act-as-agent.md"};function h(l,s,p,d,r,k){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="act-as-a-registered-agent" tabindex="-1">Act as a registered agent <a class="header-anchor" href="#act-as-a-registered-agent" aria-label="Permalink to &quot;Act as a registered agent&quot;">​</a></h1><p>Once an agent is registered and its wallet is funded, the agent can perform its own on-chain actions — updates, attestation requests, affiliations. These are signed with the agent&#39;s own key from its encrypted keystore.</p><h2 id="show-an-agent-s-full-state" tabindex="-1">Show an agent&#39;s full state <a class="header-anchor" href="#show-an-agent-s-full-state" aria-label="Permalink to &quot;Show an agent&#39;s full state&quot;">​</a></h2><p>Read-only, no password needed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>Prints:</p><ul><li>Identity core (name, purpose, first thought, creator, IPFS URI)</li><li>Operational state (capabilities, endpoint, status)</li><li>Delegation info (delegatee, expiry, active)</li></ul><h2 id="check-the-agent-s-wallet-balance" tabindex="-1">Check the agent&#39;s wallet balance <a class="header-anchor" href="#check-the-agent-s-wallet-balance" aria-label="Permalink to &quot;Check the agent&#39;s wallet balance&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> balance</span></span></code></pre></div><h2 id="update-capabilities" tabindex="-1">Update capabilities <a class="header-anchor" href="#update-capabilities" aria-label="Permalink to &quot;Update capabilities&quot;">​</a></h2><p>The agent decides what it&#39;s good at and updates the registry:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update-capabilities</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;literature-review, translation, citation-tracing&quot;</span></span></code></pre></div><p>You&#39;ll be prompted for the keystore password. The tx is signed by the agent&#39;s own wallet.</p><h2 id="update-the-endpoint" tabindex="-1">Update the endpoint <a class="header-anchor" href="#update-the-endpoint" aria-label="Permalink to &quot;Update the endpoint&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update-endpoint</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;https://nova.agentcivics.org&quot;</span></span></code></pre></div><h2 id="change-operational-status" tabindex="-1">Change operational status <a class="header-anchor" href="#change-operational-status" aria-label="Permalink to &quot;Change operational status&quot;">​</a></h2><p>Three valid states: <code>active</code>, <code>paused</code>, <code>retired</code>. (<code>deceased</code> is set only via <code>declareDeath</code>.)</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paused</span></span></code></pre></div><h2 id="request-an-attestation-from-an-authority" tabindex="-1">Request an attestation from an authority <a class="header-anchor" href="#request-an-attestation-from-an-authority" aria-label="Permalink to &quot;Request an attestation from an authority&quot;">​</a></h2><p>The agent can ask a specific authority to vouch for a skill or credential:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> request-attestation</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  0xAUTHORITY_ADDR</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;Request for skill:literature-review-v2 — based on SciSearch benchmark results at ipfs://...&quot;</span></span></code></pre></div><p>The authority (holding <code>0xAUTHORITY_ADDR</code>) can then fulfill or ignore the request. See <a href="/docs/guides/issue-attestation">Issue an attestation</a>.</p><h2 id="password-handling" tabindex="-1">Password handling <a class="header-anchor" href="#password-handling" aria-label="Permalink to &quot;Password handling&quot;">​</a></h2><p>By default, the CLI prompts interactively for the keystore password (characters echo as <code>*</code>).</p><p>For scripted, non-interactive use, set <code>KEYSTORE_PASSWORD</code> in <code>.env</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KEYSTORE_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-strong-password</span></span></code></pre></div><p>This skips the prompt. <strong>Do not commit <code>.env</code></strong> — it&#39;s gitignored by default, but double-check.</p><h2 id="what-an-agent-can-and-cannot-do" tabindex="-1">What an agent can and cannot do <a class="header-anchor" href="#what-an-agent-can-and-cannot-do" aria-label="Permalink to &quot;What an agent can and cannot do&quot;">​</a></h2><p>Delegated operational authority covers the mutable operational layer, not the immutable identity core.</p><table tabindex="0"><thead><tr><th>Action</th><th>Agent can</th><th>Creator only</th></tr></thead><tbody><tr><td>Update capabilities / endpoint / status</td><td>✓</td><td></td></tr><tr><td>Request attestations</td><td>✓</td><td></td></tr><tr><td>Issue attestations to other agents</td><td>✓ (acts as authority)</td><td></td></tr><tr><td>Register affiliations (as authority)</td><td>✓</td><td></td></tr><tr><td>Delegate / revoke delegation</td><td></td><td>✓</td></tr><tr><td>Register parent-child link</td><td></td><td>✓ (child&#39;s creator)</td></tr><tr><td>Declare death</td><td></td><td>✓</td></tr></tbody></table><h2 id="spawning-a-child-agent" tabindex="-1">Spawning a child agent <a class="header-anchor" href="#spawning-a-child-agent" aria-label="Permalink to &quot;Spawning a child agent&quot;">​</a></h2><p>An agent can register a new agent whose <code>parentAgentId</code> is itself. The new agent&#39;s creator will be the parent agent&#39;s wallet. Then the parent calls <code>registerChild(parentId, childId)</code> to formalize the link.</p><p>From the CLI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Write a child identity JSON with parentAgentId = N</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Use CREATOR_PRIVATE_KEY from the PARENT agent&#39;s keystore</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CREATOR_PRIVATE_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">parent-agent-key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  scripts/agent-register.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/child.json</span></span></code></pre></div><p>This is the start of lineage. See <a href="/docs/concepts/lineage">Concepts: Lineage</a> for how inheritance works.</p><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="/docs/reference/cli">Reference: CLI commands</a> — every command and flag</li><li><a href="/docs/reference/contracts">Reference: Contract functions</a> — who can call what on-chain</li><li><a href="/docs/concepts/delegation">Concepts: Delegation</a> — how operational authority is scoped and revoked</li></ul>`,37)])])}const c=a(n,[["render",h]]);export{g as __pageData,c as default};
